mapper.select:
SELECT COUNT(*)
FROM site_menu
WHERE deleted = false
  AND menu_code = #{menuCode}

  AND id != #{excludeId}

mapper.update:
UPDATE site_menu
SET
    deleted = true,
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}

UPDATE site_menu
SET sort_order = #{sortOrder}
WHERE id = #{id}
  AND deleted = false

mapper.select:
SELECT , pm.menu_name AS parent_menu_name, b.board_name AS board_name, b.board_code AS board_code, sp.page_code AS page_code, sp.page_title AS page_title, (SELECT COUNT(*) FROM site_menu child WHERE child.parent_id = sm.id AND child.deleted = false AND child.is_visible = true) AS child_count FROM site_menu sm LEFT JOIN site_menu pm ON sm.parent_id = pm.id AND pm.deleted = false LEFT JOIN board b ON sm.board_id = b.id AND b.deleted = false LEFT JOIN site_page sp ON sm.page_id = sp.id AND sp.deleted = false WHERE sm.deleted = false AND sm.is_visible = true AND (sm.start_at IS NULL OR sm.start_at <= NOW()) AND (sm.end_at IS NULL OR sm.end_at >= NOW())
AND sm.is_login_required = #{isLoginRequired}
ORDER BY sm.depth ASC, sm.sort_order ASC, sm.id ASC
